mapper.update:
UPDATE child_menu
name = #{name}, menu_icon = #{menu_icon}, menu_href = #{menu_href}, index_page = #{index_page}, menu_id = #{menu_id},
WHERE id = #{id};

mapper.select:
SELECT  

,menu.id as menu_id1 
,menu.name as menu_name1 
,menu.menu_icon as menu_menu_icon1 
,menu.index_page as menu_index_page1 
,menu.create_time as menu_create_time1 
FROM child_menu su

left join menu menu on menu.id=su.menu_id
where 1 = 1
  and su.id = #{id}  
  and su.name = #{name}  
  and su.menu_icon = #{menu_icon}  
  and su.menu_href = #{menu_href}  
  and su.index_page = #{index_page}  
  and su.menu_id = #{menu_id}  
  and su.create_time = #{create_time}

SELECT  

,menu_id.id as menu_id_id1 
,menu_id.name as menu_id_name1 
,menu_id.menu_icon as menu_id_menu_icon1 
,menu_id.index_page as menu_id_index_page1 
,menu_id.create_time as menu_id_create_time1 
FROM child_menu su

left join menu menu_id on menu_id.id=su.menu_id
where 1 = 1
  and su.id = #{pd.id}  
